function extractFiles(node) {
  let results = [];

  if (Array.isArray(node)) {
    node.forEach(item => {
      results = results.concat(extractFiles(item));
    });
  } else if (node && typeof node === "object") {
    // If it is a file object → return it
    if (node.file_id && node.file_path) {
      results.push(node);
      return results;
    }

    // Otherwise, keep scanning its children
    Object.values(node).forEach(value => {
      results = results.concat(extractFiles(value));
    });
  }

  return results;
}

